Page._content:
:root {
  /* CodeArts 页专属覆盖样式（不影响其他子页面） */
}

body.codearts-page main.container {
  width: 100%;
  max-width: none;
  margin: 0;
  padding: 0;
}

/* 首屏：按参考图重做，左拼图 + 右文案 */
body.codearts-page .codearts-poster {
  width: 100vw;
  margin: 0 0 8px;
  margin-left: calc((100vw - 100%) / -2);
  padding: 56px 0;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0;
  align-items: center;
  background: #f1f5fb;
  overflow: hidden;
}

body.codearts-page .codearts-left {
  width: 100%;
  display: flex;
  justify-content: flex-start;
  align-items: center;
  padding-left: 0;
}

body.codearts-page .codearts-mask-stack {
  position: relative;
  width: min(70vw, 820px);
  height: min(58vh, 560px);
  margin-left: -150px;
  filter: drop-shadow(0 18px 30px rgba(2, 16, 32, 0.16));
}

body.codearts-page .mask-card {
  position: absolute;
  overflow: hidden;
  border-radius: 18px;
  border: 10px solid rgba(255, 255, 255, 0.94);
  background: #ffffff;
  isolation: isolate;
}

body.codearts-page .mask-card::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(145deg, rgba(9, 19, 35, 0.22), rgba(9, 19, 35, 0.04) 46%, rgba(255, 255, 255, 0.12));
  mix-blend-mode: multiply;
  pointer-events: none;
}

body.codearts-page .mask-card img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

body.codearts-page .mask-a {
  left: -2%;
  top: 18px;
  width: 48%;
  height: 52%;
  transform: rotate(-13deg);
  z-index: 1;
}

body.codearts-page .mask-b {
  left: 22%;
  top: 4%;
  width: 44%;
  height: 48%;
  transform: rotate(-4deg);
  z-index: 2;
}

body.codearts-page .mask-c {
  right: -2%;
  top: 2%;
  width: 38%;
  height: 44%;
  transform: rotate(12deg);
  z-index: 3;
}

body.codearts-page .mask-d {
  left: 6%;
  bottom: -2%;
  width: 46%;
  height: 42%;
  transform: rotate(8deg);
  z-index: 4;
}

body.codearts-page .mask-e {
  right: 0;
  bottom: 0;
  width: 40%;
  height: 40%;
  transform: rotate(-10deg);
  z-index: 5;
}

body.codearts-page .codearts-right {
  padding: 0 72px;
  max-width: 760px;
}

body.codearts-page .poster-title {
  margin: 10px 0 14px;
  font-size: clamp(46px, 4.4vw, 72px);
  line-height: 1.05;
  letter-spacing: -0.8px;
}

body.codearts-page .poster-sub {
  margin: 0 0 18px;
  font-size: 18px;
  line-height: 1.8;
}

body.codearts-page .poster-note {
  margin: 0 0 16px;
}

body.codearts-page .feature-strip {
  width: 100vw;
  margin-left: calc((100vw - 100%) / -2);
}

@media (max-width: 960px) {
  body.codearts-page .codearts-poster {
    grid-template-columns: 1fr;
    gap: 34px;
    padding: 38px 0;
  }
  body.codearts-page .codearts-mask-stack {
    margin-left: -72px;
    width: min(84vw, 620px);
    height: min(46vh, 440px);
  }
  body.codearts-page .codearts-right {
    padding: 0 30px;
  }
}

