}

// ==============================================
// 【修复】豪华图表：直接使用累计数据
// ==============================================
function renderAdvanceChart(data) {
  const chartDom = document.getElementById("advance-chart");
  if (!chartDom) {
    console.error("❌ 找不到豪华图表容器#advance-chart");
