    },
    xAxis: {
      type: "category",
      data: dates,
      axisLabel: { color: CONFIG.theme.text },
      axisLine: { lineStyle: { color: "#ccc" } }
    },
    yAxis: {
      type: "value",
      axisLabel: { color: CONFIG.theme.text },
      axisLine: { lineStyle: { color: "#ccc" } },
      splitLine: { lineStyle: { color: "#f0f0f0" } }
    },
    series: [{
      name: "总AC数",
      type: "line",
      data: solvedList,
      smooth: true,
      lineStyle: { width: 3, color: CONFIG.theme.total },
      itemStyle: { color: CONFIG.theme.total },
      symbol: "circle",
