          }, {
            offset: 1,
            color: `${CONFIG.theme.total}00`
          }]
        }
      }
    }]
  });

  window.addEventListener("resize", () => chart.resize());
  console.log("✅ 原版总题数图表渲染完成");
}

// ==============================================
// 【修复】豪华图表：直接使用累计数据
// ==============================================
function renderAdvanceChart(data) {
