      borderColor: 'transparent',
      textStyle: { color: '#fff' },
      axisPointer: {
        type: 'cross',
        lineStyle: { color: '#fff', type: 'dashed' }
      }
    },
    legend: {
      data: ['总题数', '简单', '中等', '困难'],
      top: 50,
      left: 'center',
      textStyle: { color: CONFIG.theme.text },
      icon: 'roundRect',
      itemWidth: 12,
      itemHeight: 12
    },
    grid: {
      left: '3%',
      right: '4%',
      bottom: '8%',
      top: '18%',
      containLabel: true
    },
    xAxis: {
      type: "category",
      data: dates,
      axisLabel: {
        color: CONFIG.theme.text,
        rotate: 30,
        interval: 'auto'
      },
      axisLine: { lineStyle: { color: "#ccc" } },
      axisTick: { lineStyle: { color: "#ccc" } }
    },
    yAxis: {
      type: "value",
      axisLabel: { color: CONFIG.theme.text },
      axisLine: { lineStyle: { color: "#ccc" } },
      axisTick: { lineStyle: { color: "#ccc" } },
      splitLine: { lineStyle: { color: "#f0f0f0" } },
      min: 0
    },
    series: [
      {
        name: '总题数',
        type: 'line',
        data: data.map(i=>i.solved),
        smooth: true,
        symbolSize: 8,
        lineStyle: { width: 3, color: CONFIG.theme.total },
        itemStyle: { color: CONFIG.theme.total },
        areaStyle: {
          color: {
            type: "linear",
            x: 0,
            y: 0,
            x2: 0,
            y: 1,
            colorStops: [{ offset: 0, color: `${CONFIG.theme.total}60` }, { offset: 1, color: `${CONFIG.theme.total}00` }]
