:root {
  /* doing 页专属覆盖样式（不影响其他子页面） */
}
body.doing-page .codearts-poster {
  padding: 56px 0;
  gap: 0;
  background: #f7f9fc;
  overflow: hidden; /* 裁掉左侧拼图出框的多余部分，避免盖住下方内容 */
}
body.doing-page .codearts-left {
  justify-content: flex-start;
  align-items: center;
}
/* doing 页：参考图的菱形相册拼图（外圈 8 图 + 中心文案） */
body.doing-page .doing-diamond2 {
  /* 覆盖 diamond-grid 的默认偏移，贴左更像参考图 */
  left: 0;
  top: 0;
  margin-left: -220px;
  width: min(66vh, 700px);
  height: min(66vh, 700px);
  /* 关键：保持整体 45° 旋转，才能得到参考图那种“紧凑菱形拼图”排列 */
  transform: rotate(45deg);

  /* 去掉你说的“白色框/白底” */
  padding: 0;
  background: transparent;
  box-shadow: none;

  /* 仍然保留适度间距（露出页面背景即可，不用白底框） */
  gap: 14px;
}
body.doing-page .doing-diamond2 .dcell {
  /* 取消 subpage.css 的 rotate(-45deg)：格子不要回正，保持菱形外观 */
  transform: none;
  /* 这里不再使用 clip-path；菱形由“旋转后的正方形格子”自然形成 */
  background: transparent;
}
body.doing-page .doing-diamond2 .dcell img {
  position: absolute;
  inset: 0;
  width: 140%;
  height: 140%;
  left: -20%;
  top: -20%;
  object-fit: cover;
  /* 图片回正（容器旋转45°，图片反向旋转45°），并放大避免露白 */
  transform: rotate(-45deg) scale(1.05);
  transform-origin: center;
}
body.doing-page .codearts-right {
  padding: 0 72px;
  max-width: 720px;
}
body.doing-page .poster-title {
  font-size: clamp(40px, 4.2vw, 64px);
  line-height: 1.08;
  letter-spacing: -0.6px;
}
body.doing-page .poster-sub {
  font-size: 18px;
}

@media (max-width: 960px) {
  body.doing-page .codearts-poster {
    gap: 34px;
    padding: 38px 0;
  }
  body.doing-page .doing-diamond2 {
    margin-left: -120px;
    width: min(56vh, 580px);
    height: min(56vh, 580px);
    gap: 12px;
    padding: 0;
  }
  body.doing-page .codearts-right {
    padding: 0 30px;
  }
}

@media (max-width: 640px) {
  body.doing-page .doing-diamond2 {
    margin-left: -80px;
    width: min(48vh, 480px);
    height: min(48vh, 480px);
    gap: 10px;
    padding: 0;
  }
}

