.hw-slide-desc { color: var(--hw-muted); margin: 0 0 14px; line-height: 1.8; }
.hw-slide-actions { display: flex; gap: 12px; flex-wrap: wrap; }
.hw-btn { display: inline-flex; align-items: center; justify-content: center; gap: 8px; padding: 10px 14px; border-radius: 10px; text-decoration: none; color: var(--hw-text); border: 1px solid var(--hw-border); background: rgba(2,16,32,0.02); }
.hw-btn:hover { background: rgba(2,16,32,0.05); }
.hw-btn-primary { background: linear-gradient(135deg, #0aa2c0, #66e6ff); border-color: rgba(10,162,192,.25); color: #03131c; font-weight: 900; }
.hw-carousel-dots { position: absolute; left: 20px; bottom: 16px; display: flex; gap: 8px; }
.hw-carousel-dots button { width: 8px; height: 8px; border-radius: 50%; border: 0; background: rgba(2,16,32,0.25); cursor: pointer; }
.hw-carousel-dots button.is-active { background: #021021; }

/* 分区 */
.hw-section { padding: 36px 0; }
.hw-section-alt { background: #f3f7ff; }
.hw-section-head { margin-bottom: 14px; }
.hw-title { margin: 8px 0 0; font-size: 26px; letter-spacing: -.2px; }

/* 第一张图风格：经典首屏 */
.classic-hero-wrap { padding-top: 20px; }
.classic-hero {
  height: 420px;
  border-radius: 18px;
  overflow: hidden;
  background: url('./封1.jpg') center/cover no-repeat, linear-gradient(135deg,#dfefff,#f5fbff);
  box-shadow: var(--shadow);
  position: relative;
}
.classic-hero::after{
  content:"";
  position:absolute;inset:0;
  background: linear-gradient(180deg, rgba(255,255,255,0.02), rgba(255,255,255,0.25) 65%, rgba(255,255,255,0.85));
}
.classic-title {
  position: absolute; left: 18px; bottom: 16px;
  font-size: 34px; font-weight: 900; color: #1a2a3a;
  text-shadow: 0 2px 8px rgba(255,255,255,.65);
}
/* 全宽铺满（更成熟简洁） */
.classic-hero-wrap .classic-hero{
  margin-left: calc((100vw - 100%) / -2);
  width: 100vw;
  border-radius: 0;
}
@media (max-width: 960px){
  .classic-hero{ height: 320px; background-size: 160% auto; background-position: center 40%; }
}
.classic-tabs {
  margin-top: 10px;
  display: grid; grid-auto-flow: column; gap: 8px;
  overflow-x: auto; padding-bottom: 6px;
}
.classic-tab {
  text-decoration: none; color: var(--text);
  background: #ffffff; border: 1px solid var(--hw-border);
  border-radius: 10px; padding: 10px 14px;
}
.classic-tab:hover { background: #f7fbff; }
.classic-panel {
  margin-top: 12px;
  border-radius: 18px;
  border: 1px solid var(--hw-border);
  background: #ffffff;
  display: grid; grid-template-columns: 300px 1fr; gap: 16px;
  padding: 16px;
}
.classic-left {
  display: grid; grid-template-rows: 160px auto;
  gap: 12px;
}
.classic-avatar {
  width: 160px; height: 160px; border-radius: 999px;
  background: url('./头像.jpg') center/cover no-repeat, linear-gradient(135deg,#eef6ff,#fafcff);
  border: 6px solid #ffffff;
  box-shadow: 0 10px 30px rgba(2,16,32,.12);
  justify-self: center;
}
.classic-meta { list-style: none; padding: 0; margin: 0; color: var(--muted); line-height: 1.9; }
.classic-right { display: grid; gap: 12px; }
.classic-block { border: 1px solid var(--hw-border); border-radius: 14px; background: #ffffff; padding: 14px; }
.classic-block-title { margin: 0 0 8px; font-size: 18px; font-weight: 900; }
.classic-text { margin: 0; color: var(--muted); line-height: 1.9; }
.classic-list { margin: 0; padding-left: 18px; color: var(--muted); line-height: 1.9; }
@media (max-width: 960px) {
  .classic-panel { grid-template-columns: 1fr; }
  .classic-left { grid-template-rows: auto auto; }
}

/* Tabs */
.hw-tabs-bar { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 12px; }
.hw-tab { padding: 8px 12px; border-radius: 999px; border: 1px solid var(--hw-border); background: #ffffff; color: var(--hw-text); cursor: pointer; }
.hw-tab.is-active { border-color: rgba(10,162,192,.3); box-shadow: 0 0 0 4px rgba(10,162,192,.08); }
.hw-tabs-panels .hw-tab-panel { display: none; }
.hw-tabs-panels .hw-tab-panel.is-active { display: block; }

/* 卡片 */
.hw-card-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 14px; }
.hw-card { display: block; text-decoration: none; color: var(--hw-text); border: 1px solid var(--hw-border); border-radius: var(--hw-radius); background: var(--hw-card); padding: 16px; transition: transform 220ms ease, border-color 160ms ease, background 160ms ease, box-shadow 160ms ease; animation: float 6s ease-in-out infinite; }
.hw-card:hover { transform: translateY(-4px); border-color: rgba(10,162,192,.25); box-shadow: 0 16px 36px rgba(2,16,32,0.12); background: #ffffff; }
.hw-card-tag { font-size: 12px; color: #0aa2c0; margin-bottom: 8px; }
.hw-card-title { font-weight: 900; }
.hw-card-desc { color: var(--hw-muted); margin-top: 6px; line-height: 1.7; font-size: 13px; }

/* 解决方案 */
.hw-solutions { display: grid; grid-template-columns: repeat(3, 1fr); gap: 14px; }
.hw-solutions.hw-solutions-two { grid-template-columns: repeat(2, 1fr); }
.hw-solution { display: block; border: 1px solid var(--hw-border); border-radius: var(--hw-radius); background: linear-gradient(135deg, #ffffff, #f7fbff); padding: 18px; color: var(--hw-text); text-decoration: none; transition: transform 220ms ease, border-color 160ms ease, box-shadow 160ms ease; animation: float 7.2s ease-in-out infinite; }
.hw-solution:hover { transform: translateY(-4px); border-color: rgba(230,0,0,.2); box-shadow: 0 16px 36px rgba(2,16,32,0.12); }
.hw-solution-title { font-weight: 900; }
.hw-solution-desc { color: var(--hw-muted); margin-top: 8px; line-height: 1.7; font-size: 13px; }

/* 分栏推荐 */
.hw-split { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }
.hw-split-card { border: 1px solid var(--hw-border); border-radius: var(--hw-radius); background: var(--hw-card); padding: 16px; animation: float 7.8s ease-in-out infinite; }
.hw-split-title { margin: 8px 0 6px; font-size: 20px; }
.hw-split-desc { color: var(--hw-muted); margin: 0 0 12px; line-height: 1.8; }
.hw-bridge { padding-top: 8px; padding-bottom: 10px; }
.hw-bridge .hw-split-card { min-height: 140px; }
.hw-bridge-list {
  margin: 0;
  padding-left: 20px;
  color: var(--hw-muted);
  line-height: 1.9;
}

/* 支持与服务 */
.hw-support { display: grid; grid-template-columns: repeat(3, 1fr); gap: 14px; }
.hw-support-item { border: 1px solid var(--hw-border); border-radius: var(--hw-radius); background: var(--hw-card); padding: 16px; animation: float 6.6s ease-in-out infinite; }
.hw-support-title { font-weight: 900; }
.hw-support-desc { color: var(--hw-muted); margin-top: 6px; }

/* 关于 */
.hw-about { color: var(--hw-muted); line-height: 1.9; }
.hw-about a { color: #0aa2c0; }
.hw-suggest-box {
  margin-top: 12px;
  max-width: 760px;
  display: grid;
  gap: 8px;
}
.hw-suggest-label {
  font-weight: 800;
  color: var(--hw-text);
}
.hw-suggest-input {
  width: 100%;
  border: 1px solid var(--hw-border);
  border-radius: 10px;
  background: #ffffff;
  color: var(--hw-text);
  padding: 10px 12px;
  resize: vertical;
  font: inherit;
}
.hw-suggest-input:focus {
  outline: none;
  border-color: #0aa2c0;
  box-shadow: 0 0 0 3px rgba(10,162,192,.12);
}

/* Footer */
.hw-footer { background: #ffffff; border-top: 1px solid var(--hw-border); margin-top: 10px; }
.hw-footer-grid { display: grid; grid-template-columns: 2fr 1fr 1fr 1fr; gap: 14px; padding: 24px 0; }
.hw-footer-brand { font-weight: 900; font-size: 18px; }
.hw-footer-text { color: var(--hw-muted); margin-top: 8px; line-height: 1.7; }
.hw-footer-title { font-weight: 900; margin-bottom: 10px; }
.hw-footer-link { display: block; color: var(--hw-muted); text-decoration: none; padding: 6px 0; }
.hw-footer-link:hover { color: var(--hw-text); }
.hw-footer-bottom { border-top: 1px solid var(--hw-border); background: #ffffff; }
.hw-footer-bottom-inner { display: flex; align-items: center; justify-content: space-between; padding: 14px 0; color: var(--hw-muted); }
.hw-footer-bottom-links { display: flex; gap: 12px; }

/* 漂浮与装饰特效 */
@keyframes float {
  0% { transform: translateY(0px); }
  50% { transform: translateY(-6px); }
  100% { transform: translateY(0px); }
}

.hw-slide-content { animation: float 7s ease-in-out infinite; }
.hw-banner::before,
.hw-banner::after {
  content: "";
  position: absolute;
  pointer-events: none;
  inset: auto auto 12px 12px;
  width: 160px;
  height: 160px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, rgba(10,162,192,.18), rgba(102,230,255,.08), transparent 70%);
  filter: blur(0.6px);
  animation: drift 18s linear infinite;
}
.hw-banner::after {
  left: auto;
  right: 12px;
  width: 220px;
  height: 220px;
  animation-duration: 22s;
  background: radial-gradient(circle at 30% 30%, rgba(255,90,90,.16), rgba(230,0,0,.06), transparent 70%);
}
@keyframes drift {
  0% { transform: translateY(0) translateX(0); opacity: .9; }
  50% { transform: translateY(-8px) translateX(6px); opacity: .7; }
  100% { transform: translateY(0) translateX(0); opacity: .9; }
}

@media (prefers-reduced-motion: reduce) {
  .hw-card, .hw-solution, .hw-split-card, .hw-support-item, .hw-slide-content {
    animation: none !important;
  }
}

/* 响应式 */
@media (max-width: 1080px) {
  .hw-card-grid, .hw-solutions { grid-template-columns: 1fr 1fr; }
  .hw-footer-grid { grid-template-columns: 1fr 1fr; }
}
@media (max-width: 860px) {
  .hw-nav-toggle { display: inline-flex; align-items: center; justify-content: center; }
  .hw-nav-list { display: none; position: absolute; left: 0; top: 46px; background: #ffffff; border: 1px solid var(--hw-border); border-radius: 12px; padding: 10px; box-shadow: var(--shadow); }
  .hw-nav-list.open { display: grid; gap: 6px; }
  .hw-search-input { width: 140px; }
  .hw-split { grid-template-columns: 1fr; }
}
@media (max-width: 640px) {
  .hw-card-grid, .hw-solutions, .hw-support { grid-template-columns: 1fr; }
  .hw-footer-grid { grid-template-columns: 1fr; }
  .hw-slide { min-height: 280px; padding: 22px; }
  .hw-slide-title { font-size: 28px; }
}

