      ctx.beginPath();
      ctx.fillStyle = `rgba(102, 230, 255, ${s.a * 0.18})`;
      ctx.arc(s.x, s.y, s.r * 2.2, 0, Math.PI * 2);
      ctx.fill();
    }

    rafId = window.requestAnimationFrame(draw);
  }

  function startStars() {
    if (!canvas || !ctx) return;
    resizeCanvas();
    createStars();
    if (prefersReduced) {
      // Draw once; keep it lightweight for reduced motion.
      draw();
      window.cancelAnimationFrame(rafId);
      return;
    }
    rafId = window.requestAnimationFrame(draw);
  }

  window.addEventListener("resize", () => {
    resizeCanvas();
    createStars();
  });

  startStars();

  // ----- Nav active + smooth scroll -----
  const navLinks = $$(".nav-link");
  const sectionIds = navLinks.map((a) => a.dataset.section).filter(Boolean);
  const sections = sectionIds.map((id) => document.getElementById(id)).filter(Boolean);

  function setActiveById(id) {
    navLinks.forEach((a) => {
      a.classList.toggle("active", a.dataset.section === id);
    });
  }

  const io = new IntersectionObserver(
    (entries) => {
      // pick the entry with largest intersection ratio
      const visible = entries
        .filter((e) => e.isIntersecting)
        .sort((a, b) => (b.intersectionRatio ?? 0) - (a.intersectionRatio ?? 0))[0];
      if (visible?.target?.id) setActiveById(visible.target.id);
    },
    { root: null, threshold: [0.2, 0.35, 0.5, 0.65], rootMargin: "-10% 0px -70% 0px" }
  );
  sections.forEach((s) => io.observe(s));
  setActiveById("home");

  navLinks.forEach((a) => {
    a.addEventListener("click", (e) => {
      const href = a.getAttribute("href") || "";
      if (!href.startsWith("#")) return;
      e.preventDefault();
      const target = $(href);
      target?.scrollIntoView({ behavior: "smooth", block: "start" });
      setActiveById(target?.id);

      // close mobile menu if open
      const nav = $(".nav");
      nav?.classList.remove("open");
      const btn = $(".nav-toggle");
      if (btn) btn.setAttribute("aria-expanded", "false");
    });
  });

  // ----- Mobile nav toggle -----
  const navToggle = $(".nav-toggle");
  navToggle?.addEventListener("click", () => {
    const nav = $(".nav");
    if (!nav) return;
    const isOpen = nav.classList.toggle("open");
    navToggle.setAttribute("aria-expanded", String(isOpen));
  });

  // ----- Scroll progress bar -----
  const scrollBar = $(".scroll-bar");
  function updateProgress() {
    if (!scrollBar) return;
    const doc = document.documentElement;
    const max = Math.max(1, doc.scrollHeight - window.innerHeight);
    const p = Math.min(1, Math.max(0, window.scrollY / max));
    scrollBar.style.width = `${p * 100}%`;
  }
  updateProgress();
  window.addEventListener("scroll", updateProgress, { passive: true });

  // ----- Back to top button -----
  const toTopBtn = $("#toTopBtn");
  const onTop = () => {
    if (!toTopBtn) return;
    toTopBtn.classList.toggle("show", window.scrollY > 600);
  };
  onTop();
  window.addEventListener("scroll", onTop, { passive: true });
  toTopBtn?.addEventListener("click", () => {
    document.documentElement.scrollIntoView({ behavior: "smooth", block: "start" });
  });

  // ----- Copy email -----
  const email = "weitinting@demo.com";
  const emailValue = $("#emailValue");
  if (emailValue) emailValue.textContent = email;

  function copyText(text) {
    if (!text) return Promise.resolve(false);
    if (navigator.clipboard?.writeText) {
      return navigator.clipboard
        .writeText(text)
        .then(() => true)
        .catch(() => false);
    }
    // Fallback: best-effort
    return new Promise((resolve) => {
      try {
        const ta = document.createElement("textarea");
        ta.value = text;
        ta.style.position = "fixed";
        ta.style.left = "-9999px";
        ta.style.top = "-9999px";
        document.body.appendChild(ta);
        ta.select();
        const ok = document.execCommand("copy");
        document.body.removeChild(ta);
        resolve(ok);
      } catch {
        resolve(false);
      }
    });
  }

  async function onCopy(btn) {
    if (!btn) return;
    const formHint = $("#formHint");
    const ok = await copyText(email);
    if (formHint) {
      formHint.textContent = ok ? "已复制邮箱到剪贴板。" : "复制失败，请手动复制邮箱。";
      window.setTimeout(() => {
        formHint.textContent = "";
      }, 2200);
    }
    btn.textContent = ok ? "已复制" : "复制邮箱";
    window.setTimeout(() => {
      btn.textContent = "复制邮箱";
    }, 1600);
  }

  $("#copyEmailBtn")?.addEventListener("click", (e) => onCopy(e.currentTarget));
  $("#copyEmailBtn2")?.addEventListener("click", (e) => onCopy(e.currentTarget));

  // ----- Contact form demo -----
  const contactForm = $("#contactForm");
  const formHint = $("#formHint");
  contactForm?.addEventListener("submit", (e) => {
    e.preventDefault();
    if (formHint) {
      formHint.textContent = "已在本地模拟提交（无后端）。你可以接入自己的接口。";
      window.setTimeout(() => (formHint.textContent = ""), 2600);
    }
    contactForm.reset();
  });

  // ----- Footer year -----
  $("#year").textContent = String(new Date().getFullYear());
})();

Page._content:
:root {
  --bg0: #06161f;
  --bg1: #071d28;
  --bg2: #0a2737;
  --card: rgba(10, 33, 48, 0.58);
  --card2: rgba(12, 44, 63, 0.38);
  --border: rgba(140, 214, 255, 0.18);
  --border2: rgba(255, 255, 255, 0.12);
  --text: rgba(235, 249, 255, 0.92);
  --muted: rgba(235, 249, 255, 0.68);
  --muted2: rgba(235, 249, 255, 0.54);
  --accent: #66e6ff;
  --accent2: #a56bff;
  --accent3: #ff8a5b;
  --shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
  --radius: 20px;
  --container: 1100px;
}

* {
  box-sizing: border-box;
}

html,
body {
  height: 100%;
}

body {
  margin: 0;
  font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "Apple Color Emoji",
    "Segoe UI Emoji";
  color: var(--text);
  background:
    radial-gradient(1200px 600px at 30% -10%, rgba(102, 230, 255, 0.22), transparent 60%),
    radial-gradient(900px 520px at 90% 20%, rgba(165, 107, 255, 0.18), transparent 55%),
    radial-gradient(800px 380px at 60% 110%, rgba(255, 138, 91, 0.10), transparent 60%),
    linear-gradient(180deg, var(--bg0), var(--bg1) 35%, var(--bg2));
  overflow-x: hidden;
}

canvas#stars {
  position: fixed;
  inset: 0;
  width: 100%;
  height: 100%;
  z-index: -1;
  pointer-events: none;
}

/* Subtle vignette */
body::before {
  content: "";
  position: fixed;
  inset: 0;
  background:
    radial-gradient(1000px 500px at 50% 20%, rgba(0, 0, 0, 0), rgba(0, 0, 0, 0.55) 75%),
    radial-gradient(1000px 700px at 50% 110%, rgba(0, 0, 0, 0), rgba(0, 0, 0, 0.6) 70%);
  pointer-events: none;
  z-index: -1;
}

.container {
  width: min(var(--container), calc(100% - 40px));
  margin: 0 auto;
}

.site-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 20;
  padding: 14px 0;
  background: linear-gradient(180deg, rgba(6, 22, 31, 0.82), rgba(6, 22, 31, 0.35));
  backdrop-filter: blur(10px);
  border-bottom: 1px solid rgba(140, 214, 255, 0.09);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 20px;
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  text-decoration: none;
  color: var(--text);
  font-weight: 700;
  letter-spacing: 0.2px;
}

.brand-dot {
  width: 10px;
  height: 10px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, #fff, var(--accent) 50%, rgba(102, 230, 255, 0) 72%);
  box-shadow: 0 0 0 6px rgba(102, 230, 255, 0.10);
}

.nav {
  display: flex;
  align-items: center;
  gap: 18px;
}

.nav-link {
  color: var(--muted);
  text-decoration: none;
  font-size: 14px;
  padding: 10px 10px;
  border-radius: 999px;
  border: 1px solid transparent;
  transition: all 160ms ease;
}

.nav-link:hover {
  color: var(--text);
  border-color: rgba(140, 214, 255, 0.18);
  background: rgba(8, 36, 52, 0.35);
}

.nav-link.active {
  color: rgba(240, 255, 255, 0.95);
  border-color: rgba(102, 230, 255, 0.28);
  background: linear-gradient(180deg, rgba(102, 230, 255, 0.14), rgba(165, 107, 255, 0.08));
  box-shadow: 0 0 0 4px rgba(102, 230, 255, 0.06);
}

.nav-toggle {
  display: none;
  appearance: none;
  border: 1px solid rgba(140, 214, 255, 0.18);
  background: rgba(8, 36, 52, 0.35);
  color: var(--text);
  width: 42px;
  height: 42px;
  border-radius: 12px;
  cursor: pointer;
}

/* Hero */
.hero {
  padding-top: 86px; /* fixed header */
  padding-bottom: 52px;
}

.hero-grid {
  display: grid;
  grid-template-columns: 320px 1fr;
  gap: 34px;
  align-items: start;
}

.profile-card {
  position: relative;
  background: linear-gradient(180deg, rgba(13, 44, 64, 0.64), rgba(10, 33, 48, 0.40));
  border: 1px solid rgba(140, 214, 255, 0.16);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  padding: 18px;
  overflow: hidden;
}

.profile-card::after {
  content: "";
  position: absolute;
  inset: -100px -60px auto -60px;
  height: 240px;
  background: radial-gradient(circle at 20% 30%, rgba(102, 230, 255, 0.25), transparent 60%),
    radial-gradient(circle at 65% 20%, rgba(165, 107, 255, 0.16), transparent 55%);
  pointer-events: none;
}

.profile-top {
  position: relative;
  display: flex;
  gap: 14px;
  align-items: center;
}

.avatar {
  width: 68px;
  height: 68px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, rgba(255, 255, 255, 0.9), rgba(102, 230, 255, 0.35), rgba(165, 107, 255, 0.18));
  border: 1px solid rgba(255, 255, 255, 0.18);
  box-shadow: 0 0 0 7px rgba(102, 230, 255, 0.08);
  display: grid;
  place-items: center;
}

.avatar span {
  color: rgba(5, 16, 22, 0.92);
  font-weight: 900;
  letter-spacing: 0.6px;
}

.profile-name {
  font-weight: 800;
  font-size: 16px;
}

.profile-title {
  margin-top: 4px;
  font-size: 12px;
  color: var(--muted);
}

.profile-sub {
  position: relative;
  margin-top: 14px;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.chip {
  font-size: 12px;
  color: rgba(235, 249, 255, 0.88);
  padding: 6px 10px;
  border-radius: 999px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.28);
}

.profile-desc {
  position: relative;
  margin: 14px 0 0;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.6;
}

.social-row {
  position: relative;
  display: flex;
  gap: 10px;
  margin-top: 16px;
}

.social-btn {
  width: 40px;
  height: 40px;
  border-radius: 12px;
  display: grid;
  place-items: center;
  color: rgba(235, 249, 255, 0.86);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.26);
  text-decoration: none;
  transition: transform 140ms ease, background 140ms ease, border-color 140ms ease;
}

.social-btn:hover {
  transform: translateY(-2px);
  border-color: rgba(102, 230, 255, 0.25);
  background: rgba(8, 36, 52, 0.42);
}

.profile-stats {
  position: relative;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
  margin-top: 16px;
}

.stat {
  padding: 10px 10px 12px;
  border-radius: 14px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(4, 18, 26, 0.26);
}

.stat-num {
  font-weight: 900;
  font-size: 14px;
  letter-spacing: 0.3px;
}

.stat-label {
  margin-top: 6px;
  color: var(--muted2);
  font-size: 11px;
  line-height: 1.2;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  border-radius: 14px;
  padding: 12px 16px;
  border: 1px solid rgba(140, 214, 255, 0.18);
  background: rgba(8, 36, 52, 0.25);
  color: var(--text);
  text-decoration: none;
  cursor: pointer;
  transition: transform 140ms ease, background 140ms ease, border-color 140ms ease;
  font-weight: 650;
}

.btn:hover {
  transform: translateY(-1px);
  border-color: rgba(102, 230, 255, 0.3);
}

.btn-primary {
  width: 100%;
  margin-top: 14px;
  background: linear-gradient(135deg, rgba(102, 230, 255, 0.35), rgba(165, 107, 255, 0.22));
  border-color: rgba(102, 230, 255, 0.35);
  box-shadow: 0 0 0 5px rgba(102, 230, 255, 0.08);
}

.btn-primary:active {
  transform: translateY(0px);
}

.btn-arrow {
  opacity: 0.9;
}

.btn-ghost {
  background: transparent;
  border-color: rgba(140, 214, 255, 0.16);
  color: rgba(235, 249, 255, 0.92);
}

.btn-soft {
  background: linear-gradient(180deg, rgba(8, 36, 52, 0.24), rgba(8, 36, 52, 0.36));
}

.btn-wide {
  width: 100%;
}

.hero-right {
  padding-top: 8px;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: 999px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.22);
  color: rgba(235, 249, 255, 0.84);
  font-size: 13px;
}

.badge-dot {
  width: 8px;
  height: 8px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, #fff, rgba(102, 230, 255, 0.75) 50%, rgba(102, 230, 255, 0) 70%);
  box-shadow: 0 0 18px rgba(102, 230, 255, 0.45);
}

.hero-title {
  margin: 16px 0 10px;
  font-size: 44px;
  line-height: 1.05;
  letter-spacing: -0.8px;
}

.hero-title-gradient {
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.95), rgba(165, 107, 255, 0.95), rgba(255, 138, 91, 0.90));
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

.hero-subtitle {
  margin: 0;
  color: var(--muted);
  font-size: 14px;
  line-height: 1.8;
  max-width: 640px;
}

.hero-actions {
  display: flex;
  gap: 14px;
  flex-wrap: wrap;
  margin-top: 18px;
}

.metric-row {
  margin-top: 20px;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 14px;
}

.metric-card {
  border-radius: 18px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: linear-gradient(180deg, rgba(9, 40, 58, 0.35), rgba(7, 26, 39, 0.18));
  padding: 18px 16px;
  position: relative;
  overflow: hidden;
}

.metric-card::after {
  content: "";
  position: absolute;
  inset: -120px -80px auto -80px;
  height: 220px;
  background: radial-gradient(circle at 40% 50%, rgba(102, 230, 255, 0.18), transparent 60%);
}

.metric-num {
  position: relative;
  font-weight: 900;
  font-size: 28px;
  letter-spacing: -0.5px;
}

.metric-plus {
  font-size: 16px;
  opacity: 0.9;
  margin-left: 1px;
}

.metric-label {
  position: relative;
  margin-top: 10px;
  color: var(--muted2);
  font-size: 12px;
  line-height: 1.3;
}

.hero-divider {
  height: 1px;
  margin: 28px 0 16px;
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.0), rgba(102, 230, 255, 0.32), rgba(165, 107, 255, 0.0));
  opacity: 0.85;
}

.story-title {
  font-weight: 800;
  color: rgba(235, 249, 255, 0.92);
  margin-bottom: 10px;
}

.story-body {
  display: grid;
  grid-template-columns: 24px 1fr;
  gap: 16px;
  align-items: start;
}

.story-line {
  width: 2px;
  height: 180px;
  background: linear-gradient(180deg, rgba(102, 230, 255, 0), rgba(102, 230, 255, 0.45), rgba(165, 107, 255, 0.0));
  margin-left: 10px;
  border-radius: 2px;
}

.story-items {
  display: grid;
  gap: 14px;
}

.story-item {
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(4, 18, 26, 0.22);
  border-radius: 16px;
  padding: 14px 14px;
}

.story-when {
  color: rgba(235, 249, 255, 0.9);
  font-weight: 800;
  font-size: 12px;
}

.story-what {
  margin-top: 8px;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.6;
}

/* Sections */
.section {
  padding: 56px 0;
}

.section-head {
  text-align: left;
  margin-bottom: 22px;
}

.section-kicker {
  color: rgba(102, 230, 255, 0.9);
  font-weight: 800;
  letter-spacing: 0.25px;
  font-size: 13px;
}

.section-title {
  margin: 10px 0 10px;
  font-size: 28px;
  letter-spacing: -0.3px;
}

.section-desc {
  margin: 0;
  color: var(--muted);
  max-width: 760px;
  line-height: 1.8;
}

.grid-3 {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}

.feature-card,
.project-card {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.22);
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.18);
}

.feature-card {
  padding: 18px 18px 16px;
}

.feature-icon {
  width: 44px;
  height: 44px;
  border-radius: 16px;
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, rgba(102, 230, 255, 0.18), rgba(165, 107, 255, 0.10));
  border: 1px solid rgba(102, 230, 255, 0.18);
  font-weight: 900;
}

.feature-title {
  margin-top: 14px;
  font-weight: 850;
}

.feature-text {
  margin-top: 8px;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.7;
}

.project-card {
  padding: 18px;
  text-decoration: none;
  color: var(--text);
  display: flex;
  flex-direction: column;
  gap: 12px;
  transition: transform 160ms ease, border-color 160ms ease, background 160ms ease;
}

.project-card:hover {
  transform: translateY(-4px);
  border-color: rgba(102, 230, 255, 0.25);
  background: rgba(8, 36, 52, 0.30);
}

.project-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.project-tag {
  font-size: 12px;
  color: rgba(235, 249, 255, 0.9);
  padding: 7px 10px;
  border-radius: 999px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(4, 18, 26, 0.22);
}

.project-icon {
  font-size: 24px;
  opacity: 0.9;
}

.project-name {
  font-weight: 900;
  letter-spacing: -0.2px;
  font-size: 18px;
}

.project-desc {
  color: var(--muted);
  font-size: 13px;
  line-height: 1.65;
}

.project-foot {
  margin-top: auto;
  color: rgba(235, 249, 255, 0.75);
  font-size: 12px;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
  padding-top: 12px;
}

/* Timeline */
.timeline {
  position: relative;
  margin-top: 12px;
  display: grid;
  gap: 14px;
}

.timeline-item {
  display: grid;
  grid-template-columns: 120px 1fr;
  gap: 16px;
}

.timeline-year {
  display: flex;
  align-items: center;
  justify-content: flex-start;
  color: rgba(235, 249, 255, 0.88);
  font-weight: 900;
  letter-spacing: 0.3px;
}

.timeline-card {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.22);
  padding: 18px;
}

.timeline-title {
  font-weight: 900;
}

.timeline-text {
  margin-top: 8px;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.7;
}

/* Skills */
.skills-wrap {
  display: grid;
  gap: 14px;
  margin-top: 8px;
}

.skill {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.18);
  padding: 16px;
}

.skill-top {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 10px;
}

.skill-name {
  font-weight: 850;
}

.skill-percent {
  color: rgba(102, 230, 255, 0.92);
  font-weight: 900;
}

.skill-bar {
  margin-top: 10px;
  height: 10px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.08);
  overflow: hidden;
}

.skill-fill {
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.9), rgba(165, 107, 255, 0.8), rgba(255, 138, 91, 0.75));
  box-shadow: 0 0 16px rgba(102, 230, 255, 0.25);
}

/* Contact */
.contact-grid {
  display: grid;
  grid-template-columns: 1fr 360px;
  gap: 16px;
  align-items: start;
}

.contact-card {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.18);
  padding: 18px;
}

.field {
  display: grid;
  gap: 8px;
  margin-bottom: 14px;
}

.label {
  color: rgba(235, 249, 255, 0.86);
  font-weight: 750;
  font-size: 13px;
}

.input,
.textarea {
  width: 100%;
  border-radius: 14px;
  padding: 12px 12px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(4, 18, 26, 0.25);
  color: var(--text);
  outline: none;
}

.textarea {
  resize: vertical;
  min-height: 130px;
}

.input:focus,
.textarea:focus {
  border-color: rgba(102, 230, 255, 0.3);
  box-shadow: 0 0 0 4px rgba(102, 230, 255, 0.08);
}

.form-hint {
  margin-top: 10px;
  color: rgba(102, 230, 255, 0.92);
  font-size: 13px;
  min-height: 18px;
}

.contact-side {
  display: grid;
  gap: 16px;
}

.contact-mini,
.contact-note {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.18);
  padding: 16px;
}

.contact-mini-title {
  font-weight: 900;
  margin-bottom: 10px;
}

.contact-mini-row {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 12px;
  padding: 8px 0;
  border-top: 1px dashed rgba(255, 255, 255, 0.10);
}

.contact-mini-row:first-of-type {
  border-top: 0;
}

.contact-mini-label {
  color: var(--muted2);
  font-size: 13px;
}

.contact-mini-value {
  font-weight: 850;
  font-size: 13px;
  color: rgba(235, 249, 255, 0.9);
  text-align: right;
  word-break: break-word;
}

.contact-mini-actions {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  margin-top: 14px;
}

.contact-note-title {
  font-weight: 900;
  margin-bottom: 10px;
}

.contact-note-text {
  color: var(--muted);
  font-size: 13px;
  line-height: 1.7;
}

/* Footer */
.footer {
  padding: 24px 0 40px;
  border-top: 1px solid rgba(140, 214, 255, 0.09);
}

.footer-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

.footer-brand {
  font-weight: 900;
}

.footer-left {
  color: rgba(235, 249, 255, 0.86);
}

.footer-sep {
  opacity: 0.55;
  margin: 0 8px;
}

.footer-link {
  color: rgba(102, 230, 255, 0.92);
  text-decoration: none;
  font-weight: 750;
}

.footer-link:hover {
  text-decoration: underline;
}

/* Scroll indicator + back to top */
.scroll-indicator {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  z-index: 30;
  pointer-events: none;
  background: rgba(255, 255, 255, 0.04);
}

.scroll-bar {
  height: 100%;
  width: 0%;
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.95), rgba(165, 107, 255, 0.85), rgba(255, 138, 91, 0.8));
  box-shadow: 0 0 20px rgba(102, 230, 255, 0.35);
}

.to-top {
  position: fixed;
  right: 18px;
  bottom: 18px;
  z-index: 30;
  width: 46px;
  height: 46px;
  border-radius: 16px;
  border: 1px solid rgba(140, 214, 255, 0.16);
  background: rgba(8, 36, 52, 0.45);
  color: var(--text);
  cursor: pointer;
  display: grid;
  place-items: center;
  box-shadow: 0 18px 50px rgba(0, 0, 0, 0.35);
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 200ms ease, transform 200ms ease, border-color 140ms ease;
}

.to-top.show {
  opacity: 1;
  transform: translateY(0);
}

.to-top:hover {
  border-color: rgba(102, 230, 255, 0.28);
}

/* Responsive */
@media (max-width: 980px) {
  .hero-grid {
    grid-template-columns: 1fr;
  }
  .metric-row {
    grid-template-columns: repeat(2, 1fr);
  }
  .grid-3 {
    grid-template-columns: 1fr;
  }
  .timeline-item {
    grid-template-columns: 90px 1fr;
  }
  .contact-grid {
    grid-template-columns: 1fr;
  }
  .contact-side {
    order: 2;
  }
}

@media (max-width: 720px) {
  .nav {
    display: none;
    position: absolute;
    left: 20px;
    right: 20px;
    top: 68px;
    padding: 12px;
    border-radius: 18px;
    border: 1px solid rgba(140, 214, 255, 0.14);
    background: rgba(6, 22, 31, 0.72);
    backdrop-filter: blur(14px);
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
  }
  .nav.open {
    display: flex;
    flex-direction: column;
    gap: 8px;
  }
  .nav-toggle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
  }
  .hero-title {
    font-size: 36px;
  }
  .metric-row {
    grid-template-columns: 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  .project-card,
  .btn,
  .social-btn,
  .to-top {
    transition: none !important;
  }
}

Page.raw:
:root {
  --bg0: #06161f;
  --bg1: #071d28;
  --bg2: #0a2737;
  --card: rgba(10, 33, 48, 0.58);
  --card2: rgba(12, 44, 63, 0.38);
  --border: rgba(140, 214, 255, 0.18);
  --border2: rgba(255, 255, 255, 0.12);
  --text: rgba(235, 249, 255, 0.92);
  --muted: rgba(235, 249, 255, 0.68);
  --muted2: rgba(235, 249, 255, 0.54);
  --accent: #66e6ff;
  --accent2: #a56bff;
  --accent3: #ff8a5b;
  --shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
  --radius: 20px;
  --container: 1100px;
}

* {
  box-sizing: border-box;
}

html,
body {
  height: 100%;
}

body {
  margin: 0;
  font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "Apple Color Emoji",
    "Segoe UI Emoji";
  color: var(--text);
  background:
    radial-gradient(1200px 600px at 30% -10%, rgba(102, 230, 255, 0.22), transparent 60%),
    radial-gradient(900px 520px at 90% 20%, rgba(165, 107, 255, 0.18), transparent 55%),
    radial-gradient(800px 380px at 60% 110%, rgba(255, 138, 91, 0.10), transparent 60%),
    linear-gradient(180deg, var(--bg0), var(--bg1) 35%, var(--bg2));
  overflow-x: hidden;
}

canvas#stars {
  position: fixed;
  inset: 0;
  width: 100%;
  height: 100%;
  z-index: -1;
  pointer-events: none;
}

/* Subtle vignette */
body::before {
  content: "";
  position: fixed;
  inset: 0;
  background:
    radial-gradient(1000px 500px at 50% 20%, rgba(0, 0, 0, 0), rgba(0, 0, 0, 0.55) 75%),
    radial-gradient(1000px 700px at 50% 110%, rgba(0, 0, 0, 0), rgba(0, 0, 0, 0.6) 70%);
  pointer-events: none;
  z-index: -1;
}

.container {
  width: min(var(--container), calc(100% - 40px));
  margin: 0 auto;
}

.site-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 20;
  padding: 14px 0;
  background: linear-gradient(180deg, rgba(6, 22, 31, 0.82), rgba(6, 22, 31, 0.35));
  backdrop-filter: blur(10px);
  border-bottom: 1px solid rgba(140, 214, 255, 0.09);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 20px;
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  text-decoration: none;
  color: var(--text);
  font-weight: 700;
  letter-spacing: 0.2px;
}

.brand-dot {
  width: 10px;
  height: 10px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, #fff, var(--accent) 50%, rgba(102, 230, 255, 0) 72%);
  box-shadow: 0 0 0 6px rgba(102, 230, 255, 0.10);
}

.nav {
  display: flex;
  align-items: center;
  gap: 18px;
}

.nav-link {
  color: var(--muted);
  text-decoration: none;
  font-size: 14px;
  padding: 10px 10px;
  border-radius: 999px;
  border: 1px solid transparent;
  transition: all 160ms ease;
}

.nav-link:hover {
  color: var(--text);
  border-color: rgba(140, 214, 255, 0.18);
  background: rgba(8, 36, 52, 0.35);
}

.nav-link.active {
  color: rgba(240, 255, 255, 0.95);
  border-color: rgba(102, 230, 255, 0.28);
  background: linear-gradient(180deg, rgba(102, 230, 255, 0.14), rgba(165, 107, 255, 0.08));
  box-shadow: 0 0 0 4px rgba(102, 230, 255, 0.06);
}

.nav-toggle {
  display: none;
  appearance: none;
  border: 1px solid rgba(140, 214, 255, 0.18);
  background: rgba(8, 36, 52, 0.35);
  color: var(--text);
  width: 42px;
  height: 42px;
  border-radius: 12px;
  cursor: pointer;
}

/* Hero */
.hero {
  padding-top: 86px; /* fixed header */
  padding-bottom: 52px;
}

.hero-grid {
  display: grid;
  grid-template-columns: 320px 1fr;
  gap: 34px;
  align-items: start;
}

.profile-card {
  position: relative;
  background: linear-gradient(180deg, rgba(13, 44, 64, 0.64), rgba(10, 33, 48, 0.40));
  border: 1px solid rgba(140, 214, 255, 0.16);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  padding: 18px;
  overflow: hidden;
}

.profile-card::after {
  content: "";
  position: absolute;
  inset: -100px -60px auto -60px;
  height: 240px;
  background: radial-gradient(circle at 20% 30%, rgba(102, 230, 255, 0.25), transparent 60%),
    radial-gradient(circle at 65% 20%, rgba(165, 107, 255, 0.16), transparent 55%);
  pointer-events: none;
}

.profile-top {
  position: relative;
  display: flex;
  gap: 14px;
  align-items: center;
}

.avatar {
  width: 68px;
  height: 68px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, rgba(255, 255, 255, 0.9), rgba(102, 230, 255, 0.35), rgba(165, 107, 255, 0.18));
  border: 1px solid rgba(255, 255, 255, 0.18);
  box-shadow: 0 0 0 7px rgba(102, 230, 255, 0.08);
  display: grid;
  place-items: center;
}

.avatar span {
  color: rgba(5, 16, 22, 0.92);
  font-weight: 900;
  letter-spacing: 0.6px;
}

.profile-name {
  font-weight: 800;
  font-size: 16px;
}

.profile-title {
  margin-top: 4px;
  font-size: 12px;
  color: var(--muted);
}

.profile-sub {
  position: relative;
  margin-top: 14px;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.chip {
  font-size: 12px;
  color: rgba(235, 249, 255, 0.88);
  padding: 6px 10px;
  border-radius: 999px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.28);
}

.profile-desc {
  position: relative;
  margin: 14px 0 0;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.6;
}

.social-row {
  position: relative;
  display: flex;
  gap: 10px;
  margin-top: 16px;
}

.social-btn {
  width: 40px;
  height: 40px;
  border-radius: 12px;
  display: grid;
  place-items: center;
  color: rgba(235, 249, 255, 0.86);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.26);
  text-decoration: none;
  transition: transform 140ms ease, background 140ms ease, border-color 140ms ease;
}

.social-btn:hover {
  transform: translateY(-2px);
  border-color: rgba(102, 230, 255, 0.25);
  background: rgba(8, 36, 52, 0.42);
}

.profile-stats {
  position: relative;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
  margin-top: 16px;
}

.stat {
  padding: 10px 10px 12px;
  border-radius: 14px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(4, 18, 26, 0.26);
}

.stat-num {
  font-weight: 900;
  font-size: 14px;
  letter-spacing: 0.3px;
}

.stat-label {
  margin-top: 6px;
  color: var(--muted2);
  font-size: 11px;
  line-height: 1.2;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  border-radius: 14px;
  padding: 12px 16px;
  border: 1px solid rgba(140, 214, 255, 0.18);
  background: rgba(8, 36, 52, 0.25);
  color: var(--text);
  text-decoration: none;
  cursor: pointer;
  transition: transform 140ms ease, background 140ms ease, border-color 140ms ease;
  font-weight: 650;
}

.btn:hover {
  transform: translateY(-1px);
  border-color: rgba(102, 230, 255, 0.3);
}

.btn-primary {
  width: 100%;
  margin-top: 14px;
  background: linear-gradient(135deg, rgba(102, 230, 255, 0.35), rgba(165, 107, 255, 0.22));
  border-color: rgba(102, 230, 255, 0.35);
  box-shadow: 0 0 0 5px rgba(102, 230, 255, 0.08);
}

.btn-primary:active {
  transform: translateY(0px);
}

.btn-arrow {
  opacity: 0.9;
}

.btn-ghost {
  background: transparent;
  border-color: rgba(140, 214, 255, 0.16);
  color: rgba(235, 249, 255, 0.92);
}

.btn-soft {
  background: linear-gradient(180deg, rgba(8, 36, 52, 0.24), rgba(8, 36, 52, 0.36));
}

.btn-wide {
  width: 100%;
}

.hero-right {
  padding-top: 8px;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: 999px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.22);
  color: rgba(235, 249, 255, 0.84);
  font-size: 13px;
}

.badge-dot {
  width: 8px;
  height: 8px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, #fff, rgba(102, 230, 255, 0.75) 50%, rgba(102, 230, 255, 0) 70%);
  box-shadow: 0 0 18px rgba(102, 230, 255, 0.45);
}

.hero-title {
  margin: 16px 0 10px;
  font-size: 44px;
  line-height: 1.05;
  letter-spacing: -0.8px;
}

.hero-title-gradient {
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.95), rgba(165, 107, 255, 0.95), rgba(255, 138, 91, 0.90));
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

.hero-subtitle {
  margin: 0;
  color: var(--muted);
  font-size: 14px;
  line-height: 1.8;
  max-width: 640px;
}

.hero-actions {
  display: flex;
  gap: 14px;
  flex-wrap: wrap;
  margin-top: 18px;
}

.metric-row {
  margin-top: 20px;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 14px;
}

.metric-card {
  border-radius: 18px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: linear-gradient(180deg, rgba(9, 40, 58, 0.35), rgba(7, 26, 39, 0.18));
  padding: 18px 16px;
  position: relative;
  overflow: hidden;
}

.metric-card::after {
  content: "";
  position: absolute;
  inset: -120px -80px auto -80px;
  height: 220px;
  background: radial-gradient(circle at 40% 50%, rgba(102, 230, 255, 0.18), transparent 60%);
}

.metric-num {
  position: relative;
  font-weight: 900;
  font-size: 28px;
  letter-spacing: -0.5px;
}

.metric-plus {
  font-size: 16px;
  opacity: 0.9;
  margin-left: 1px;
}

.metric-label {
  position: relative;
  margin-top: 10px;
  color: var(--muted2);
  font-size: 12px;
  line-height: 1.3;
}

.hero-divider {
  height: 1px;
  margin: 28px 0 16px;
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.0), rgba(102, 230, 255, 0.32), rgba(165, 107, 255, 0.0));
  opacity: 0.85;
}

.story-title {
  font-weight: 800;
  color: rgba(235, 249, 255, 0.92);
  margin-bottom: 10px;
}

.story-body {
  display: grid;
  grid-template-columns: 24px 1fr;
  gap: 16px;
  align-items: start;
}

.story-line {
  width: 2px;
  height: 180px;
  background: linear-gradient(180deg, rgba(102, 230, 255, 0), rgba(102, 230, 255, 0.45), rgba(165, 107, 255, 0.0));
  margin-left: 10px;
  border-radius: 2px;
}

.story-items {
  display: grid;
  gap: 14px;
}

.story-item {
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(4, 18, 26, 0.22);
  border-radius: 16px;
  padding: 14px 14px;
}

.story-when {
  color: rgba(235, 249, 255, 0.9);
  font-weight: 800;
  font-size: 12px;
}

.story-what {
  margin-top: 8px;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.6;
}

/* Sections */
.section {
  padding: 56px 0;
}

.section-head {
  text-align: left;
  margin-bottom: 22px;
}

.section-kicker {
  color: rgba(102, 230, 255, 0.9);
  font-weight: 800;
  letter-spacing: 0.25px;
  font-size: 13px;
}

.section-title {
  margin: 10px 0 10px;
  font-size: 28px;
  letter-spacing: -0.3px;
}

.section-desc {
  margin: 0;
  color: var(--muted);
  max-width: 760px;
  line-height: 1.8;
}

.grid-3 {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}

.feature-card,
.project-card {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.22);
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.18);
}

.feature-card {
  padding: 18px 18px 16px;
}

.feature-icon {
  width: 44px;
  height: 44px;
  border-radius: 16px;
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, rgba(102, 230, 255, 0.18), rgba(165, 107, 255, 0.10));
  border: 1px solid rgba(102, 230, 255, 0.18);
  font-weight: 900;
}

.feature-title {
  margin-top: 14px;
  font-weight: 850;
}

.feature-text {
  margin-top: 8px;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.7;
}

.project-card {
  padding: 18px;
  text-decoration: none;
  color: var(--text);
  display: flex;
  flex-direction: column;
  gap: 12px;
  transition: transform 160ms ease, border-color 160ms ease, background 160ms ease;
}

.project-card:hover {
  transform: translateY(-4px);
  border-color: rgba(102, 230, 255, 0.25);
  background: rgba(8, 36, 52, 0.30);
}

.project-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.project-tag {
  font-size: 12px;
  color: rgba(235, 249, 255, 0.9);
  padding: 7px 10px;
  border-radius: 999px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(4, 18, 26, 0.22);
}

.project-icon {
  font-size: 24px;
  opacity: 0.9;
}

.project-name {
  font-weight: 900;
  letter-spacing: -0.2px;
  font-size: 18px;
}

.project-desc {
  color: var(--muted);
  font-size: 13px;
  line-height: 1.65;
}

.project-foot {
  margin-top: auto;
  color: rgba(235, 249, 255, 0.75);
  font-size: 12px;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
  padding-top: 12px;
}

/* Timeline */
.timeline {
  position: relative;
  margin-top: 12px;
  display: grid;
  gap: 14px;
}

.timeline-item {
  display: grid;
  grid-template-columns: 120px 1fr;
  gap: 16px;
}

.timeline-year {
  display: flex;
  align-items: center;
  justify-content: flex-start;
  color: rgba(235, 249, 255, 0.88);
  font-weight: 900;
  letter-spacing: 0.3px;
}

.timeline-card {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.22);
  padding: 18px;
}

.timeline-title {
  font-weight: 900;
}

.timeline-text {
  margin-top: 8px;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.7;
}

/* Skills */
.skills-wrap {
  display: grid;
  gap: 14px;
  margin-top: 8px;
}

.skill {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.18);
  padding: 16px;
}

.skill-top {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 10px;
}

.skill-name {
  font-weight: 850;
}

.skill-percent {
  color: rgba(102, 230, 255, 0.92);
  font-weight: 900;
}

.skill-bar {
  margin-top: 10px;
  height: 10px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.08);
  overflow: hidden;
}

.skill-fill {
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.9), rgba(165, 107, 255, 0.8), rgba(255, 138, 91, 0.75));
  box-shadow: 0 0 16px rgba(102, 230, 255, 0.25);
}

/* Contact */
.contact-grid {
  display: grid;
  grid-template-columns: 1fr 360px;
  gap: 16px;
  align-items: start;
}

.contact-card {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.18);
  padding: 18px;
}

.field {
  display: grid;
  gap: 8px;
  margin-bottom: 14px;
}

.label {
  color: rgba(235, 249, 255, 0.86);
  font-weight: 750;
  font-size: 13px;
}

.input,
.textarea {
  width: 100%;
  border-radius: 14px;
  padding: 12px 12px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(4, 18, 26, 0.25);
  color: var(--text);
  outline: none;
}

.textarea {
  resize: vertical;
  min-height: 130px;
}

.input:focus,
.textarea:focus {
  border-color: rgba(102, 230, 255, 0.3);
  box-shadow: 0 0 0 4px rgba(102, 230, 255, 0.08);
}

.form-hint {
  margin-top: 10px;
  color: rgba(102, 230, 255, 0.92);
  font-size: 13px;
  min-height: 18px;
}

.contact-side {
  display: grid;
  gap: 16px;
}

.contact-mini,
.contact-note {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.18);
  padding: 16px;
}

.contact-mini-title {
  font-weight: 900;
  margin-bottom: 10px;
}

.contact-mini-row {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 12px;
  padding: 8px 0;
  border-top: 1px dashed rgba(255, 255, 255, 0.10);
}

.contact-mini-row:first-of-type {
  border-top: 0;
}

.contact-mini-label {
  color: var(--muted2);
  font-size: 13px;
}

.contact-mini-value {
  font-weight: 850;
  font-size: 13px;
  color: rgba(235, 249, 255, 0.9);
  text-align: right;
  word-break: break-word;
}

.contact-mini-actions {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  margin-top: 14px;
}

.contact-note-title {
  font-weight: 900;
  margin-bottom: 10px;
}

.contact-note-text {
  color: var(--muted);
  font-size: 13px;
  line-height: 1.7;
}

/* Footer */
.footer {
  padding: 24px 0 40px;
  border-top: 1px solid rgba(140, 214, 255, 0.09);
}

.footer-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

.footer-brand {
  font-weight: 900;
}

.footer-left {
  color: rgba(235, 249, 255, 0.86);
}

.footer-sep {
  opacity: 0.55;
  margin: 0 8px;
}

.footer-link {
  color: rgba(102, 230, 255, 0.92);
  text-decoration: none;
  font-weight: 750;
}

.footer-link:hover {
  text-decoration: underline;
}

/* Scroll indicator + back to top */
.scroll-indicator {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  z-index: 30;
  pointer-events: none;
  background: rgba(255, 255, 255, 0.04);
}

.scroll-bar {
  height: 100%;
  width: 0%;
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.95), rgba(165, 107, 255, 0.85), rgba(255, 138, 91, 0.8));
  box-shadow: 0 0 20px rgba(102, 230, 255, 0.35);
}

.to-top {
  position: fixed;
  right: 18px;
  bottom: 18px;
  z-index: 30;
  width: 46px;
  height: 46px;
  border-radius: 16px;
  border: 1px solid rgba(140, 214, 255, 0.16);
  background: rgba(8, 36, 52, 0.45);
  color: var(--text);
  cursor: pointer;
  display: grid;
  place-items: center;
  box-shadow: 0 18px 50px rgba(0, 0, 0, 0.35);
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 200ms ease, transform 200ms ease, border-color 140ms ease;
}

.to-top.show {
  opacity: 1;
  transform: translateY(0);
}

.to-top:hover {
  border-color: rgba(102, 230, 255, 0.28);
}

/* Responsive */
@media (max-width: 980px) {
  .hero-grid {
    grid-template-columns: 1fr;
  }
  .metric-row {
    grid-template-columns: repeat(2, 1fr);
  }
  .grid-3 {
    grid-template-columns: 1fr;
  }
  .timeline-item {
    grid-template-columns: 90px 1fr;
  }
  .contact-grid {
    grid-template-columns: 1fr;
  }
  .contact-side {
    order: 2;
  }
}

@media (max-width: 720px) {
  .nav {
    display: none;
    position: absolute;
    left: 20px;
    right: 20px;
    top: 68px;
    padding: 12px;
    border-radius: 18px;
    border: 1px solid rgba(140, 214, 255, 0.14);
    background: rgba(6, 22, 31, 0.72);
    backdrop-filter: blur(14px);
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
  }
  .nav.open {
    display: flex;
    flex-direction: column;
    gap: 8px;
  }
  .nav-toggle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
  }
  .hero-title {
    font-size: 36px;
  }
  .metric-row {
    grid-template-columns: 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  .project-card,
  .btn,
  .social-btn,
  .to-top {
    transition: none !important;
  }
}

Page.content:
:root {
  --bg0: #06161f;
  --bg1: #071d28;
  --bg2: #0a2737;
  --card: rgba(10, 33, 48, 0.58);
  --card2: rgba(12, 44, 63, 0.38);
  --border: rgba(140, 214, 255, 0.18);
  --border2: rgba(255, 255, 255, 0.12);
  --text: rgba(235, 249, 255, 0.92);
  --muted: rgba(235, 249, 255, 0.68);
  --muted2: rgba(235, 249, 255, 0.54);
  --accent: #66e6ff;
  --accent2: #a56bff;
  --accent3: #ff8a5b;
  --shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
  --radius: 20px;
  --container: 1100px;
}

* {
  box-sizing: border-box;
}

html,
body {
  height: 100%;
}

body {
  margin: 0;
  font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, "Apple Color Emoji",
    "Segoe UI Emoji";
  color: var(--text);
  background:
    radial-gradient(1200px 600px at 30% -10%, rgba(102, 230, 255, 0.22), transparent 60%),
    radial-gradient(900px 520px at 90% 20%, rgba(165, 107, 255, 0.18), transparent 55%),
    radial-gradient(800px 380px at 60% 110%, rgba(255, 138, 91, 0.10), transparent 60%),
    linear-gradient(180deg, var(--bg0), var(--bg1) 35%, var(--bg2));
  overflow-x: hidden;
}

canvas#stars {
  position: fixed;
  inset: 0;
  width: 100%;
  height: 100%;
  z-index: -1;
  pointer-events: none;
}

/* Subtle vignette */
body::before {
  content: "";
  position: fixed;
  inset: 0;
  background:
    radial-gradient(1000px 500px at 50% 20%, rgba(0, 0, 0, 0), rgba(0, 0, 0, 0.55) 75%),
    radial-gradient(1000px 700px at 50% 110%, rgba(0, 0, 0, 0), rgba(0, 0, 0, 0.6) 70%);
  pointer-events: none;
  z-index: -1;
}

.container {
  width: min(var(--container), calc(100% - 40px));
  margin: 0 auto;
}

.site-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 20;
  padding: 14px 0;
  background: linear-gradient(180deg, rgba(6, 22, 31, 0.82), rgba(6, 22, 31, 0.35));
  backdrop-filter: blur(10px);
  border-bottom: 1px solid rgba(140, 214, 255, 0.09);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 20px;
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  text-decoration: none;
  color: var(--text);
  font-weight: 700;
  letter-spacing: 0.2px;
}

.brand-dot {
  width: 10px;
  height: 10px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, #fff, var(--accent) 50%, rgba(102, 230, 255, 0) 72%);
  box-shadow: 0 0 0 6px rgba(102, 230, 255, 0.10);
}

.nav {
  display: flex;
  align-items: center;
  gap: 18px;
}

.nav-link {
  color: var(--muted);
  text-decoration: none;
  font-size: 14px;
  padding: 10px 10px;
  border-radius: 999px;
  border: 1px solid transparent;
  transition: all 160ms ease;
}

.nav-link:hover {
  color: var(--text);
  border-color: rgba(140, 214, 255, 0.18);
  background: rgba(8, 36, 52, 0.35);
}

.nav-link.active {
  color: rgba(240, 255, 255, 0.95);
  border-color: rgba(102, 230, 255, 0.28);
  background: linear-gradient(180deg, rgba(102, 230, 255, 0.14), rgba(165, 107, 255, 0.08));
  box-shadow: 0 0 0 4px rgba(102, 230, 255, 0.06);
}

.nav-toggle {
  display: none;
  appearance: none;
  border: 1px solid rgba(140, 214, 255, 0.18);
  background: rgba(8, 36, 52, 0.35);
  color: var(--text);
  width: 42px;
  height: 42px;
  border-radius: 12px;
  cursor: pointer;
}

/* Hero */
.hero {
  padding-top: 86px; /* fixed header */
  padding-bottom: 52px;
}

.hero-grid {
  display: grid;
  grid-template-columns: 320px 1fr;
  gap: 34px;
  align-items: start;
}

.profile-card {
  position: relative;
  background: linear-gradient(180deg, rgba(13, 44, 64, 0.64), rgba(10, 33, 48, 0.40));
  border: 1px solid rgba(140, 214, 255, 0.16);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  padding: 18px;
  overflow: hidden;
}

.profile-card::after {
  content: "";
  position: absolute;
  inset: -100px -60px auto -60px;
  height: 240px;
  background: radial-gradient(circle at 20% 30%, rgba(102, 230, 255, 0.25), transparent 60%),
    radial-gradient(circle at 65% 20%, rgba(165, 107, 255, 0.16), transparent 55%);
  pointer-events: none;
}

.profile-top {
  position: relative;
  display: flex;
  gap: 14px;
  align-items: center;
}

.avatar {
  width: 68px;
  height: 68px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, rgba(255, 255, 255, 0.9), rgba(102, 230, 255, 0.35), rgba(165, 107, 255, 0.18));
  border: 1px solid rgba(255, 255, 255, 0.18);
  box-shadow: 0 0 0 7px rgba(102, 230, 255, 0.08);
  display: grid;
  place-items: center;
}

.avatar span {
  color: rgba(5, 16, 22, 0.92);
  font-weight: 900;
  letter-spacing: 0.6px;
}

.profile-name {
  font-weight: 800;
  font-size: 16px;
}

.profile-title {
  margin-top: 4px;
  font-size: 12px;
  color: var(--muted);
}

.profile-sub {
  position: relative;
  margin-top: 14px;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.chip {
  font-size: 12px;
  color: rgba(235, 249, 255, 0.88);
  padding: 6px 10px;
  border-radius: 999px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.28);
}

.profile-desc {
  position: relative;
  margin: 14px 0 0;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.6;
}

.social-row {
  position: relative;
  display: flex;
  gap: 10px;
  margin-top: 16px;
}

.social-btn {
  width: 40px;
  height: 40px;
  border-radius: 12px;
  display: grid;
  place-items: center;
  color: rgba(235, 249, 255, 0.86);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.26);
  text-decoration: none;
  transition: transform 140ms ease, background 140ms ease, border-color 140ms ease;
}

.social-btn:hover {
  transform: translateY(-2px);
  border-color: rgba(102, 230, 255, 0.25);
  background: rgba(8, 36, 52, 0.42);
}

.profile-stats {
  position: relative;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
  margin-top: 16px;
}

.stat {
  padding: 10px 10px 12px;
  border-radius: 14px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(4, 18, 26, 0.26);
}

.stat-num {
  font-weight: 900;
  font-size: 14px;
  letter-spacing: 0.3px;
}

.stat-label {
  margin-top: 6px;
  color: var(--muted2);
  font-size: 11px;
  line-height: 1.2;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  border-radius: 14px;
  padding: 12px 16px;
  border: 1px solid rgba(140, 214, 255, 0.18);
  background: rgba(8, 36, 52, 0.25);
  color: var(--text);
  text-decoration: none;
  cursor: pointer;
  transition: transform 140ms ease, background 140ms ease, border-color 140ms ease;
  font-weight: 650;
}

.btn:hover {
  transform: translateY(-1px);
  border-color: rgba(102, 230, 255, 0.3);
}

.btn-primary {
  width: 100%;
  margin-top: 14px;
  background: linear-gradient(135deg, rgba(102, 230, 255, 0.35), rgba(165, 107, 255, 0.22));
  border-color: rgba(102, 230, 255, 0.35);
  box-shadow: 0 0 0 5px rgba(102, 230, 255, 0.08);
}

.btn-primary:active {
  transform: translateY(0px);
}

.btn-arrow {
  opacity: 0.9;
}

.btn-ghost {
  background: transparent;
  border-color: rgba(140, 214, 255, 0.16);
  color: rgba(235, 249, 255, 0.92);
}

.btn-soft {
  background: linear-gradient(180deg, rgba(8, 36, 52, 0.24), rgba(8, 36, 52, 0.36));
}

.btn-wide {
  width: 100%;
}

.hero-right {
  padding-top: 8px;
}

.hero-badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: 999px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.22);
  color: rgba(235, 249, 255, 0.84);
  font-size: 13px;
}

.badge-dot {
  width: 8px;
  height: 8px;
  border-radius: 999px;
  background: radial-gradient(circle at 30% 30%, #fff, rgba(102, 230, 255, 0.75) 50%, rgba(102, 230, 255, 0) 70%);
  box-shadow: 0 0 18px rgba(102, 230, 255, 0.45);
}

.hero-title {
  margin: 16px 0 10px;
  font-size: 44px;
  line-height: 1.05;
  letter-spacing: -0.8px;
}

.hero-title-gradient {
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.95), rgba(165, 107, 255, 0.95), rgba(255, 138, 91, 0.90));
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

.hero-subtitle {
  margin: 0;
  color: var(--muted);
  font-size: 14px;
  line-height: 1.8;
  max-width: 640px;
}

.hero-actions {
  display: flex;
  gap: 14px;
  flex-wrap: wrap;
  margin-top: 18px;
}

.metric-row {
  margin-top: 20px;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 14px;
}

.metric-card {
  border-radius: 18px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: linear-gradient(180deg, rgba(9, 40, 58, 0.35), rgba(7, 26, 39, 0.18));
  padding: 18px 16px;
  position: relative;
  overflow: hidden;
}

.metric-card::after {
  content: "";
  position: absolute;
  inset: -120px -80px auto -80px;
  height: 220px;
  background: radial-gradient(circle at 40% 50%, rgba(102, 230, 255, 0.18), transparent 60%);
}

.metric-num {
  position: relative;
  font-weight: 900;
  font-size: 28px;
  letter-spacing: -0.5px;
}

.metric-plus {
  font-size: 16px;
  opacity: 0.9;
  margin-left: 1px;
}

.metric-label {
  position: relative;
  margin-top: 10px;
  color: var(--muted2);
  font-size: 12px;
  line-height: 1.3;
}

.hero-divider {
  height: 1px;
  margin: 28px 0 16px;
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.0), rgba(102, 230, 255, 0.32), rgba(165, 107, 255, 0.0));
  opacity: 0.85;
}

.story-title {
  font-weight: 800;
  color: rgba(235, 249, 255, 0.92);
  margin-bottom: 10px;
}

.story-body {
  display: grid;
  grid-template-columns: 24px 1fr;
  gap: 16px;
  align-items: start;
}

.story-line {
  width: 2px;
  height: 180px;
  background: linear-gradient(180deg, rgba(102, 230, 255, 0), rgba(102, 230, 255, 0.45), rgba(165, 107, 255, 0.0));
  margin-left: 10px;
  border-radius: 2px;
}

.story-items {
  display: grid;
  gap: 14px;
}

.story-item {
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(4, 18, 26, 0.22);
  border-radius: 16px;
  padding: 14px 14px;
}

.story-when {
  color: rgba(235, 249, 255, 0.9);
  font-weight: 800;
  font-size: 12px;
}

.story-what {
  margin-top: 8px;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.6;
}

/* Sections */
.section {
  padding: 56px 0;
}

.section-head {
  text-align: left;
  margin-bottom: 22px;
}

.section-kicker {
  color: rgba(102, 230, 255, 0.9);
  font-weight: 800;
  letter-spacing: 0.25px;
  font-size: 13px;
}

.section-title {
  margin: 10px 0 10px;
  font-size: 28px;
  letter-spacing: -0.3px;
}

.section-desc {
  margin: 0;
  color: var(--muted);
  max-width: 760px;
  line-height: 1.8;
}

.grid-3 {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}

.feature-card,
.project-card {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.22);
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.18);
}

.feature-card {
  padding: 18px 18px 16px;
}

.feature-icon {
  width: 44px;
  height: 44px;
  border-radius: 16px;
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, rgba(102, 230, 255, 0.18), rgba(165, 107, 255, 0.10));
  border: 1px solid rgba(102, 230, 255, 0.18);
  font-weight: 900;
}

.feature-title {
  margin-top: 14px;
  font-weight: 850;
}

.feature-text {
  margin-top: 8px;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.7;
}

.project-card {
  padding: 18px;
  text-decoration: none;
  color: var(--text);
  display: flex;
  flex-direction: column;
  gap: 12px;
  transition: transform 160ms ease, border-color 160ms ease, background 160ms ease;
}

.project-card:hover {
  transform: translateY(-4px);
  border-color: rgba(102, 230, 255, 0.25);
  background: rgba(8, 36, 52, 0.30);
}

.project-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.project-tag {
  font-size: 12px;
  color: rgba(235, 249, 255, 0.9);
  padding: 7px 10px;
  border-radius: 999px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(4, 18, 26, 0.22);
}

.project-icon {
  font-size: 24px;
  opacity: 0.9;
}

.project-name {
  font-weight: 900;
  letter-spacing: -0.2px;
  font-size: 18px;
}

.project-desc {
  color: var(--muted);
  font-size: 13px;
  line-height: 1.65;
}

.project-foot {
  margin-top: auto;
  color: rgba(235, 249, 255, 0.75);
  font-size: 12px;
  border-top: 1px solid rgba(255, 255, 255, 0.08);
  padding-top: 12px;
}

/* Timeline */
.timeline {
  position: relative;
  margin-top: 12px;
  display: grid;
  gap: 14px;
}

.timeline-item {
  display: grid;
  grid-template-columns: 120px 1fr;
  gap: 16px;
}

.timeline-year {
  display: flex;
  align-items: center;
  justify-content: flex-start;
  color: rgba(235, 249, 255, 0.88);
  font-weight: 900;
  letter-spacing: 0.3px;
}

.timeline-card {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.22);
  padding: 18px;
}

.timeline-title {
  font-weight: 900;
}

.timeline-text {
  margin-top: 8px;
  color: var(--muted);
  font-size: 13px;
  line-height: 1.7;
}

/* Skills */
.skills-wrap {
  display: grid;
  gap: 14px;
  margin-top: 8px;
}

.skill {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.18);
  padding: 16px;
}

.skill-top {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 10px;
}

.skill-name {
  font-weight: 850;
}

.skill-percent {
  color: rgba(102, 230, 255, 0.92);
  font-weight: 900;
}

.skill-bar {
  margin-top: 10px;
  height: 10px;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.08);
  overflow: hidden;
}

.skill-fill {
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.9), rgba(165, 107, 255, 0.8), rgba(255, 138, 91, 0.75));
  box-shadow: 0 0 16px rgba(102, 230, 255, 0.25);
}

/* Contact */
.contact-grid {
  display: grid;
  grid-template-columns: 1fr 360px;
  gap: 16px;
  align-items: start;
}

.contact-card {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.18);
  padding: 18px;
}

.field {
  display: grid;
  gap: 8px;
  margin-bottom: 14px;
}

.label {
  color: rgba(235, 249, 255, 0.86);
  font-weight: 750;
  font-size: 13px;
}

.input,
.textarea {
  width: 100%;
  border-radius: 14px;
  padding: 12px 12px;
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(4, 18, 26, 0.25);
  color: var(--text);
  outline: none;
}

.textarea {
  resize: vertical;
  min-height: 130px;
}

.input:focus,
.textarea:focus {
  border-color: rgba(102, 230, 255, 0.3);
  box-shadow: 0 0 0 4px rgba(102, 230, 255, 0.08);
}

.form-hint {
  margin-top: 10px;
  color: rgba(102, 230, 255, 0.92);
  font-size: 13px;
  min-height: 18px;
}

.contact-side {
  display: grid;
  gap: 16px;
}

.contact-mini,
.contact-note {
  border-radius: var(--radius);
  border: 1px solid rgba(140, 214, 255, 0.14);
  background: rgba(8, 36, 52, 0.18);
  padding: 16px;
}

.contact-mini-title {
  font-weight: 900;
  margin-bottom: 10px;
}

.contact-mini-row {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 12px;
  padding: 8px 0;
  border-top: 1px dashed rgba(255, 255, 255, 0.10);
}

.contact-mini-row:first-of-type {
  border-top: 0;
}

.contact-mini-label {
  color: var(--muted2);
  font-size: 13px;
}

.contact-mini-value {
  font-weight: 850;
  font-size: 13px;
  color: rgba(235, 249, 255, 0.9);
  text-align: right;
  word-break: break-word;
}

.contact-mini-actions {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  margin-top: 14px;
}

.contact-note-title {
  font-weight: 900;
  margin-bottom: 10px;
}

.contact-note-text {
  color: var(--muted);
  font-size: 13px;
  line-height: 1.7;
}

/* Footer */
.footer {
  padding: 24px 0 40px;
  border-top: 1px solid rgba(140, 214, 255, 0.09);
}

.footer-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

.footer-brand {
  font-weight: 900;
}

.footer-left {
  color: rgba(235, 249, 255, 0.86);
}

.footer-sep {
  opacity: 0.55;
  margin: 0 8px;
}

.footer-link {
  color: rgba(102, 230, 255, 0.92);
  text-decoration: none;
  font-weight: 750;
}

.footer-link:hover {
  text-decoration: underline;
}

/* Scroll indicator + back to top */
.scroll-indicator {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  z-index: 30;
  pointer-events: none;
  background: rgba(255, 255, 255, 0.04);
}

.scroll-bar {
  height: 100%;
  width: 0%;
  background: linear-gradient(90deg, rgba(102, 230, 255, 0.95), rgba(165, 107, 255, 0.85), rgba(255, 138, 91, 0.8));
  box-shadow: 0 0 20px rgba(102, 230, 255, 0.35);
}

.to-top {
  position: fixed;
  right: 18px;
  bottom: 18px;
  z-index: 30;
  width: 46px;
  height: 46px;
  border-radius: 16px;
  border: 1px solid rgba(140, 214, 255, 0.16);
  background: rgba(8, 36, 52, 0.45);
  color: var(--text);
  cursor: pointer;
  display: grid;
  place-items: center;
  box-shadow: 0 18px 50px rgba(0, 0, 0, 0.35);
  opacity: 0;
  transform: translateY(10px);
  transition: opacity 200ms ease, transform 200ms ease, border-color 140ms ease;
}

.to-top.show {
  opacity: 1;
  transform: translateY(0);
}

.to-top:hover {
  border-color: rgba(102, 230, 255, 0.28);
}

/* Responsive */
@media (max-width: 980px) {
  .hero-grid {
    grid-template-columns: 1fr;
  }
  .metric-row {
    grid-template-columns: repeat(2, 1fr);
  }
  .grid-3 {
    grid-template-columns: 1fr;
  }
  .timeline-item {
    grid-template-columns: 90px 1fr;
  }
  .contact-grid {
    grid-template-columns: 1fr;
  }
  .contact-side {
    order: 2;
  }
}

@media (max-width: 720px) {
  .nav {
    display: none;
    position: absolute;
    left: 20px;
    right: 20px;
    top: 68px;
    padding: 12px;
    border-radius: 18px;
    border: 1px solid rgba(140, 214, 255, 0.14);
    background: rgba(6, 22, 31, 0.72);
    backdrop-filter: blur(14px);
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
  }
  .nav.open {
    display: flex;
    flex-direction: column;
    gap: 8px;
  }
  .nav-toggle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
  }
  .hero-title {
    font-size: 36px;
  }
  .metric-row {
    grid-template-columns: 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  .project-card,
  .btn,
  .social-btn,
  .to-top {
    transition: none !important;
  }
}

