    function render() {
      gallery.innerHTML = "";
      state.files.forEach((f, idx) => {
        const url = URL.createObjectURL(f);
        const item = document.createElement("div");
        item.className = "thumb";
        item.innerHTML = `<img alt="预览" src="${url}"><button class="del" title="删除">×</button>`;
